import os
import hashlib
import datetime
import json

class Archivo:
    def __init__(self, nombre, contenido):
        self.nombre = nombre
        self.contenido = contenido

    def calcular_hash(self):
        return hashlib.sha256(self.contenido.encode()).hexdigest()

class Commit:
    def __init__(self, archivos, mensaje, padre=None):
        self.archivos = archivos
        self.mensaje = mensaje
        self.padre = padre
        self.fecha = datetime.datetime.now()
        self.hash = self.calcular_hash()

    def calcular_hash(self):
        archivos_json = json.dumps({archivo.nombre: archivo.contenido for archivo in self.archivos}, sort_keys=True)
        return hashlib.sha256((archivos_json + self.mensaje + str(self.fecha)).encode()).hexdigest()

class Rama:
    def __init__(self, nombre):
        self.nombre = nombre
        self.archivos = []
        self.padre = None

class Repositorio:
    def __init__(self, nombre):
        self.nombre = nombre
        self.ramas = {}
        self.rama_actual = None

    def agregar_archivo(self, archivo):
        if self.rama_actual:
            for a in self.rama_actual.archivos:
                if a.nombre == archivo.nombre:
                    raise Exception("El archivo ya existe en la rama")
            self.rama_actual.archivos.append(archivo)
        else:
            raise Exception("No hay rama actual")

    def hacer_commit(self, mensaje):
        if self.rama_actual:
            if not self.rama_actual.archivos:
                raise Exception("No hay archivos en la rama para hacer commit")
            commit = Commit(self.rama_actual.archivos, mensaje, self.rama_actual.padre)
            self.rama_actual.padre = commit
            self.rama_actual = commit
        else:
            raise Exception("No hay rama actual")

    def crear_rama(self, nombre):
        if nombre in self.ramas:
            raise Exception("La rama ya existe")
        rama = Rama(nombre)
        rama.padre = self.rama_actual
        self.ramas[nombre] = rama
        self.rama_actual = rama

    def cambiar_rama(self, nombre):
        if nombre not in self.ramas:
            raise Exception("La rama no existe")
        self.rama_actual = self.ramas[nombre]

    def mostrar_log(self):
        if self.rama_actual:
            log = []
            commit_actual = self.rama_actual
            while commit_actual:
                log.append((commit_actual.mensaje, commit_actual.fecha, commit_actual.hash))
                commit_actual = commit_actual.padre
            for mensaje, fecha, hash in log:
                print(f"Commit {hash}: {mensaje} - {fecha}")
        else:
            raise Exception("No hay rama actual")

    def mostrar_archivos(self):
        if self.rama_actual:
            for archivo in self.rama_actual.archivos:
                print(f"{archivo.nombre}: {archivo.contenido}")
        else:
            raise Exception("No hay rama actual")

def main():
    repo = Repositorio("mi_repositorio")
    repo.crear_rama("main")
    repo.cambiar_rama("main")
    archivo1 = Archivo("archivo1.txt", "Contenido del archivo 1")
