import logging
import queue
import threading
import time
import random

class Conexion:
    def __init__(self, id):
        self.id = id
        self.conectado = False

    def conectar(self):
        self.conectado = True
        logging.info(f"Conexion {self.id} conectada")

    def desconectar(self):
        self.conectado = False
        logging.info(f"Conexion {self.id} desconectada")

    def health_check(self):
        # Simulamos un health check
        return random.choice([True, False])

class PoolConexiones:
    def __init__(self, tamano_pool, tiempo_health_check):
        if tamano_pool <= 0:
            raise ValueError("El tamaño del pool debe ser mayor que cero")
        if tiempo_health_check <= 0:
            raise ValueError("El tiempo de health check debe ser mayor que cero")

        self.tamano_pool = tamano_pool
        self.tiempo_health_check = tiempo_health_check
        self.conexiones = [Conexion(i) for i in range(tamano_pool)]
        self.colaNuevaConexion = queue.Queue(maxsize=tamano_pool)
        self.colasConexiones = [queue.Queue() for _ in range(tamano_pool)]
        self.lock = threading.Lock()

        # Iniciamos las conexiones
        for conexion in self.conexiones:
            conexion.conectar()

        # Iniciamos el health check
        self.hilo_health_check = threading.Thread(target=self.health_check)
        self.hilo_health_check.daemon = True
        self.hilo_health_check.start()

    def obtener_conexion(self):
        with self.lock:
            for cola in self.colasConexiones:
                if not cola.empty():
                    return cola.get()
            if not self.colaNuevaConexion.empty():
                return self.colaNuevaConexion.get()
            else:
                # Si no hay conexiones disponibles y el pool está lleno, esperamos
                while True:
                    for cola in self.colasConexiones:
                        if not cola.empty():
                            return cola.get()
                    if not self.colaNuevaConexion.empty():
                        return self.colaNuevaConexion.get()
                    time.sleep(0.1)

    def devolver_conexion(self, conexion):
        with self.lock:
            for cola in self.colasConexiones:
                if cola.empty():
                    cola.put(conexion)
                    break
            else:
                # Si todas las colas están llenas, esperamos
                while True:
                    for cola in self.colasConexiones:
                        if cola.empty():
                            cola.put(conexion)
                            break
                    time.sleep(0.1)

    def health_check(self):
        while True:
            with self.lock:
                for conexion in self.conexiones:
                    if not conexion.health_check():
                        logging.warning(f"Conexion {conexion.id} no respondio al health check")
                        conexion.desconectar()
                        # Esperamos un tiempo antes de reconectar
                        time.sleep(1)
                        conexion.conectar()
            time.sleep(self.tiempo_health_check)

# Ejemplo de uso
if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    pool = PoolConexiones(5, 5)

    def usar_conexion(conexion):
        logging.info(f"Usando conexion {conexion.id}")
        time.sleep(2)
        pool.devolver_conexion(conexion)

    for _ in range(10):
        conexion = pool.obtener_conexion()
        hilo = threading.Thread(target=usar_conexion, args=(conexion,))
        hilo.start()
