import threading
import time
from queue import Queue

# Configuración de logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Conexion:
    def __init__(self, host, database, user, password):
        if not all([host, database, user, password]):
            raise ValueError("Parámetros de conexión inválidos")
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.conexion = None

    def conectar(self):
        try:
            self.conexion = psycopg2.connect(
                host=self.host,
                database=self.database,
                user=self.user,
                password=self.password
            )
            logger.info(f"Conexión establecida con {self.host}")
            return True
        except psycopg2.Error as e:
            logger.error(f"Error al conectar con {self.host}: {e}")
            return False

    def desconectar(self):
        if self.conexion:
            self.conexion.close()
            logger.info(f"Conexión cerrada con {self.host}")
            self.conexion = None

    def health_check(self):
        try:
            cursor = self.conexion.cursor()
            cursor.execute("SELECT 1")
            cursor.fetchone()
            cursor.close()  # Cerrar el cursor después de su uso
            logger.info(f"Health-check exitoso en {self.host}")
            return True
        except psycopg2.Error as e:
            logger.error(f"Error en health-check con {self.host}: {e}")
            return False

class PoolDeConexiones:
    def __init__(self, num_conexiones, host, database, user, password):
        self.num_conexiones = num_conexiones
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.conexiones = []
        self.lock = threading.Lock()
        self.queue = Queue()

    def crear_conexiones(self):
        for _ in range(self.num_conexiones):
            conexion = Conexion(self.host, self.database, self.user, self.password)
            if conexion.conectar():
                self.conexiones.append(conexion)
                self.queue.put(conexion)

    def obtener_conexion(self):
        with self.lock:
            try:
                return self.queue.get(block=False)
            except:
                logger.error("No hay conexiones disponibles")
                raise Exception("No hay conexiones disponibles")

    def devolver_conexion(self, conexion):
        with self.lock:
            self.queue.put(conexion)

    def health_check(self):
        with self.lock:
            for conexion in self.conexiones:
                if not conexion.health_check():
                    conexion.desconectar()
                    if not conexion.conectar():
                        logger.error(f"Conexión {conexion.host} no se pudo restablecer")
                        # Intentar reconectar la conexión fallida
                        for _ in range(3):  # Intentar reconectar 3 veces
                            if conexion.conectar():
                                break
                        else:
                            logger.error(f"Conexión {conexion.host} no se pudo restablecer después de 3 intentos")

def main():
    # Configuración del pool de conexiones
    num_conexiones = 5
    host = "localhost"
    database = "mi_base_de_datos"
    user = "mi_usuario"
    password = "mi_contraseña"
    pool = PoolDeConexiones(num_conexiones, host, database, user, password)
    pool.crear_conexiones()

    # Ejecución concurrente de health-checks
    def ejecutar_health_check(pool):
        while True:
            pool.health_check()
            time.sleep(60)

    threading.Thread(target=ejecutar_health_check, args=(pool,)).start()

if __name__ == "__main__":
    main()
