import re

class Token:
    """Representa un token en el lenguaje de programación."""

    def __init__(self, tipo, valor):
        """
        Inicializa un token con su tipo y valor.

        Args:
            tipo (str): El tipo del token (por ejemplo, 'IDENTIFICADOR', 'ENTERO', etc.).
            valor (str o int): El valor del token.
        """
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        """Retorna una representación en cadena del token."""
        return f'Token({self.tipo}, {self.valor})'


class Tokenizador:
    """Tokeniza el código fuente del lenguaje de programación."""

    def __init__(self, codigo):
        """
        Inicializa el tokenizador con el código fuente.

        Args:
            codigo (str): El código fuente a tokenizar.
        """
        self.codigo = codigo
        self.posicion = 0
        self.linea = 1
        self.columna = 0

    def obtener_token(self):
        """
        Obtiene el siguiente token en el código fuente.

        Returns:
            Token: El siguiente token en el código fuente, o Token('EOF', None) si se ha llegado al final del código.
        """
        if self.posicion >= len(self.codigo):
            return Token('EOF', None)

        if self.codigo[self.posicion].isspace():
            self.avanzar()
            return self.obtener_token()

        if self.codigo[self.posicion] == '#':
            self.comentario()
            return self.obtener_token()

        if self.codigo[self.posicion] == '"':
            return self.cadena()

        if self.codigo[self.posicion].isalpha():
            return self.identificador()

        if self.codigo[self.posicion].isdigit():
            return self.entero()

        if self.codigo[self.posicion] in '+-**()':
            token = Token('OPERADOR', self.codigo[self.posicion])
            self.avanzar()
            return token

        raise Exception(f'Caracter no reconocido {self.codigo[self.posicion]} en la linea {self.linea}, columna {self.columna}')

    def avanzar(self):
        """
        Avanza a la siguiente posición en el código fuente.

        Actualiza la posición, línea y columna según sea necesario.
        """
        self.posicion += 1
        self.columna += 1
        if self.codigo[self.posicion - 1] == '\n':
            self.linea += 1
            self.columna = 0

    def comentario(self):
        """
        Salta el comentario actual en el código fuente.

