# Clase Lexer para tokenizar la expresión regular
class Lexer:
    def __init__(self, texto):
        self.texto = texto
        self.posicion = 0

    def obtener_siguiente_token(self):
        if self.posicion >= len(self.texto):
            return Token(TokenType.EOF, None)

        caracter = self.texto[self.posicion]

        # Manejo de literales
        if caracter.isalnum() or caracter == "_":
            inicio = self.posicion
            while self.posicion < len(self.texto) and (self.texto[self.posicion].isalnum() or self.texto[self.posicion] == "_"):
                self.posicion += 1
            return Token(TokenType.LITERAL, self.texto[inicio:self.posicion])

        # Manejo de punto
        if caracter == ".":
            self.posicion += 1
            return Token(TokenType.PUNTO, caracter)

        # Manejo de barra vertical
        if caracter == "|":
            self.posicion += 1
            return Token(TokenType.BARRA_VERTICAL, caracter)

        # Manejo de asterisco
        if caracter == "*":
            self.posicion += 1
            return Token(TokenType.ASTERISCO, caracter)

        # Manejo de más
        if caracter == "+":
            self.posicion += 1
            return Token(TokenType.MAS, caracter)

        # Manejo de interrogación
        if caracter == "?":
            self.posicion += 1
            return Token(TokenType.INTERROGACION, caracter)

        # Manejo de paréntesis izquierdo
        if caracter == "(":
            self.posicion += 1
            return Token(TokenType.PARENTESIS_IZQUIERDO, caracter)

        # Manejo de paréntesis derecho
        if caracter == ")":
            self.posicion += 1
            return Token(TokenType.PARENTESIS_DERECHO, caracter)

        # Manejo de corchete izquierdo
        if caracter == "[":
            self.posicion += 1
            return Token(TokenType.CORCHETE_IZQUIERDO, caracter)

        # Manejo de corchete derecho
        if caracter == "]":
            self.posicion += 1
            return Token(TokenType.CORCHETE_DERECHO, caracter)

        # Manejo de caracter especial
        if caracter == "\\":
            self.posicion += 1
            if self.posicion < len(self.texto):
                caracter = self.texto[self.posicion]
                self.posicion += 1
                return Token(TokenType.CARACTER_ESPECIAL, caracter)
            else:
                raise Exception("Caracter especial al final del texto")

        # Manejo de caracteres no reconocidos
        raise Exception(f"Caracter no reconocido: {caracter}")

