        self.tipo = tipo

class Modelo:
    def __init__(self, nombre: str, campos: List[Campo]):
        self.nombre = nombre
        self.campos = campos

    def crear_tabla(self, conexion: sqlite3.Connection):
        cursor = conexion.cursor()
        campos_sql = ", ".join(f"{campo.nombre} {campo.tipo}" for campo in self.campos)
        cursor.execute(f"CREATE TABLE IF NOT EXISTS {self.nombre} (id INTEGER PRIMARY KEY, {campos_sql})")
        conexion.commit()

    def insertar(self, conexion: sqlite3.Connection, datos: Dict[str, Any]):
        if not datos:
            raise ValueError("No se proporcionaron datos para insertar")

        cursor = conexion.cursor()
        nombres_campos = ", ".join(campo.nombre for campo in self.campos)
        valores = ", ".join("?" for _ in self.campos)

        # Verificar que los datos contengan todos los campos requeridos
        for campo in self.campos:
            if campo.nombre not in datos:
                raise ValueError(f"Falta el campo {campo.nombre} en los datos")

        cursor.execute(f"INSERT INTO {self.nombre} ({nombres_campos}) VALUES ({valores})", [datos[campo.nombre] for campo in self.campos])
        conexion.commit()

    def seleccionar(self, conexion: sqlite3.Connection, condiciones: Dict[str, Any] = None):
        if condiciones is None:
            condiciones = {}

        cursor = conexion.cursor()

        # Verificar que las condiciones contengan solo campos válidos
        for nombre in condiciones:
            if not any(campo.nombre == nombre for campo in self.campos):
                raise ValueError(f"El campo {nombre} no existe en el modelo")

        if condiciones:
            condiciones_sql = " AND ".join(f"{nombre} = ?" for nombre in condiciones)
            cursor.execute(f"SELECT * FROM {self.nombre} WHERE {condiciones_sql}", list(condiciones.values()))
        else:
            cursor.execute(f"SELECT * FROM {self.nombre}")

        # Utilizar fetchmany para obtener los registros de a pocos en lugar de fetchall
        return cursor.fetchmany(100)

class ORM:
    def __init__(self, nombre_base_de_datos: str):
        self.nombre_base_de_datos = nombre_base_de_datos
        try:
            self.conexion = sqlite3.connect(nombre_base_de_datos)
        except sqlite3.Error as e:
            raise ValueError(f"Error al conectar a la base de datos: {e}")

        self.modelos = {}

    def registrar_modelo(self, modelo: Modelo):
        if modelo.nombre in self.modelos:
            raise ValueError(f"El modelo {modelo.nombre} ya está registrado")

        self.modelos[modelo.nombre] = modelo
        modelo.crear_tabla(self.conexion)

    def migrar(self):
        if not self.conexion:
            raise ValueError("No hay conexión a la base de datos")

        for modelo in self.modelos.values():
            modelo.crear_tabla(self.conexion)

    def insertar(self, nombre_modelo: str, datos: Dict[str, Any]):
        if not datos:
            raise ValueError("No se proporcionaron datos para insertar")

        modelo = self.modelos.get(nombre_modelo)
        if not modelo:
            raise ValueError(f"El modelo {nombre_modelo} no está registrado")

        modelo.insertar(self.conexion, datos)

    def seleccionar(self, nombre_modelo: str, condiciones: Dict[str, Any] = None):
        if condiciones is None:
            condiciones = {}

        modelo = self.modelos.get(nombre_modelo)
        if not modelo:
            raise ValueError(f"El modelo {nombre_modelo} no está registrado")

        return modelo.seleccionar(self.conexion, condiciones)

