class PubSubSystem:
    def __init__(self):
        self.subscribers = {}

    def subscribe(self, topic: str, predicate, callback):
        """
        Suscribirse a un tema con un predicado y callback.

        Args:
            topic (str): El tema al que suscribirse.
            predicate: El predicado para filtrar los mensajes.
            callback: La función a llamar cuando se recibe un mensaje.

        Raises:
            TypeError: Si topic no es una cadena.
            ValueError: Si topic es una cadena vacía.
        """
        if not isinstance(topic, str):
            raise TypeError("El tema debe ser una cadena")
        if not topic:
            raise ValueError("El tema no puede ser vacío")
        if predicate is None or callback is None:
            raise ValueError("El predicado y callback no pueden ser None")

        if topic not in self.subscribers:
            self.subscribers[topic] = []
        # Evitar suscripciones duplicadas
        if (predicate, callback) not in self.subscribers[topic]:
            self.subscribers[topic].append((predicate, callback))

    def unsubscribe(self, topic: str, predicate, callback):
        """
        Desuscribirse de un tema con un predicado y callback.

        Args:
            topic (str): El tema del que desuscribirse.
            predicate: El predicado para filtrar los mensajes.
            callback: La función a dejar de llamar cuando se recibe un mensaje.

        Raises:
            TypeError: Si topic no es una cadena.
            ValueError: Si topic es una cadena vacía o no existe.
        """
        if not isinstance(topic, str):
            raise TypeError("El tema debe ser una cadena")
        if not topic:
            raise ValueError("El tema no puede ser vacío")
        if topic not in self.subscribers:
            raise ValueError("El tema no existe")

        # Buscar y eliminar la suscripción
        for i, (p, c) in enumerate(self.subscribers[topic]):
            if p is predicate and c is callback:
                del self.subscribers[topic][i]
                break

    def publish(self, topic: str, message):
        """
        Publicar un mensaje en un tema.

        Args:
            topic (str): El tema en el que publicar.
            message: El mensaje a publicar.

        Raises:
            TypeError: Si topic no es una cadena.
            ValueError: Si topic es una cadena vacía o no existe.
        """
        if not isinstance(topic, str):
            raise TypeError("El tema debe ser una cadena")
        if not topic:
            raise ValueError("El tema no puede ser vacío")
        if topic not in self.subscribers:
            raise ValueError("El tema no existe")
        if message is None:
            raise ValueError("El mensaje no puede ser None")

        # Llamar a los callbacks de los suscriptores que coinciden con el predicado
        for predicate, callback in self.subscribers[topic]:
            if predicate(message):
                callback(message)


