import datetime
import json

class Archivo:
    def __init__(self, nombre, contenido):
        if not nombre:
            raise ValueError("El nombre del archivo no puede estar vacío")
        if not contenido:
            raise ValueError("El contenido del archivo no puede estar vacío")
        self.nombre = nombre
        self.contenido = contenido

    def calcular_hash(self):
        return hashlib.sha256(self.contenido.encode()).hexdigest()

class Commit:
    def __init__(self, archivos, mensaje, padre=None):
        if not mensaje:
            raise ValueError("El mensaje del commit no puede estar vacío")
        self.archivos = archivos
        self.mensaje = mensaje
        self.padre = padre
        self.fecha = datetime.datetime.now()
        self.hash = self.calcular_hash()

    def calcular_hash(self):
        archivos_hash = {archivo.nombre: archivo.calcular_hash() for archivo in self.archivos}
        return hashlib.sha256(json.dumps(archivos_hash, sort_keys=True).encode()).hexdigest()

class Repositorio:
    def __init__(self, ruta):
        self.ruta = ruta
        self.commits = []
        self.archivos = {}

    def agregar_archivo(self, archivo):
        if archivo.nombre in self.archivos:
            raise ValueError("El archivo ya existe en el repositorio")
        self.archivos[archivo.nombre] = archivo

    def hacer_commit(self, mensaje):
        if not mensaje:
            raise ValueError("El mensaje del commit no puede estar vacío")
        archivos = list(self.archivos.values())
        if self.commits:
            commit = Commit(archivos, mensaje, self.commits[-1].hash)
        else:
            commit = Commit(archivos, mensaje)
        self.commits.append(commit)
        self.guardar_commit(commit)

    def guardar_commit(self, commit):
        with open(os.path.join(self.ruta, 'commits', commit.hash), 'w') as f:
            json.dump({
                'archivos': {archivo.nombre: archivo.calcular_hash() for archivo in commit.archivos},
                'mensaje': commit.mensaje,
                'padre': commit.padre,
                'fecha': commit.fecha.isoformat()
            }, f)

    def cargar_commit(self, hash):
        archivo_commit = os.path.join(self.ruta, 'commits', hash)
        if not os.path.exists(archivo_commit):
