        with open(archivo_commit, 'r') as f:
            datos = json.load(f)
            archivos = [Archivo(nombre, '') for nombre in datos['archivos']]
            commit = Commit(archivos, datos['mensaje'], datos['padre'])
            commit.fecha = datetime.datetime.fromisoformat(datos['fecha'])
            return commit

