import typing
import uuid

class PubSub:
    def __init__(self):
        self.subscribers = {}

    def subscribe(self, topic: str, predicate: typing.Callable[[object], bool]) -> str:
        """
        Suscribirse a un tema con un filtro por predicado.

        :param topic: Tema al que suscribirse.
        :param predicate: Función que devuelve True si el mensaje es de interés.
        :return: Identificador único de la suscripción.
        """
        if not topic:
            raise ValueError("El tema no puede ser vacío")

        if topic not in self.subscribers:
            self.subscribers[topic] = {}

        subscription_id = str(uuid.uuid4())
        self.subscribers[topic][subscription_id] = predicate

        return subscription_id

    def unsubscribe(self, topic: str, subscription_id: str) -> None:
        """
        Desuscribirse de un tema.

        :param topic: Tema del que desuscribirse.
        :param subscription_id: Identificador único de la suscripción.
        """
        if topic in self.subscribers and subscription_id in self.subscribers[topic]:
            del self.subscribers[topic][subscription_id]
            if not self.subscribers[topic]:
                del self.subscribers[topic]

    def publish(self, topic: str, message: object) -> None:
        """
        Publicar un mensaje en un tema.

        :param topic: Tema en el que publicar.
        :param message: Mensaje a publicar.
        """
        if not topic:
            raise ValueError("El tema no puede ser vacío")

        if message is None:
            raise ValueError("El mensaje no puede ser None")

        if topic in self.subscribers:
            for predicate in self.subscribers[topic].values():
                try:
                    if predicate(message):
                        print(f"Mensaje '{message}' publicado en '{topic}' y filtrado por {predicate.__name__}")
                except Exception as e:
                    print(f"Error al aplicar el filtro {predicate.__name__}: {str(e)}")

