class TokenType(enum.Enum):
    LITERAL = 1
    CLASE_CARACTER = 2
    ABRE_PAREN = 3
    CIERRA_PAREN = 4
    CUANTIFICADOR = 5
    OR = 6
    EOF = 7
    CIERRA_CORCHETE = 8

class Token:
    def __init__(self, tipo, valor):
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        return f'Token({self.tipo}, {self.valor})'

class Lexer:
    def __init__(self, texto):
        self.texto = texto
        self.pos = 0
        self.tokens = []

    def obtener_siguiente_token(self):
        if not self.texto:
            return Token(TokenType.EOF, None)

        if self.pos >= len(self.texto):
            return Token(TokenType.EOF, None)

        caracter = self.texto[self.pos]

        if caracter.isspace():
            self.pos += 1
            return self.obtener_siguiente_token()

        if caracter.isalpha() or caracter.isdigit() or caracter in ['.', '_', '-']:
            token = ''
            while self.pos < len(self.texto) and (self.texto[self.pos].isalpha() or self.texto[self.pos].isdigit() or self.texto[self.pos] in ['.', '_', '-']):
                token += self.texto[self.pos]
                self.pos += 1
            return Token(TokenType.LITERAL, token)

        if caracter == '[':
            self.pos += 1
            token = ''
            while self.pos < len(self.texto) and self.texto[self.pos] != ']':
                token += self.texto[self.pos]
                self.pos += 1
            if self.pos < len(self.texto) and self.texto[self.pos] == ']':
                self.pos += 1
                return Token(TokenType.CLASE_CARACTER, token)
            else:
                raise Exception('Corchete de cierre no encontrado')

        if caracter == '(':
            self.pos += 1
            return Token(TokenType.ABRE_PAREN, caracter)

        if caracter == ')':
            self.pos += 1
            return Token(TokenType.CIERRA_PAREN, caracter)

        if caracter == '*':
            self.pos += 1
            return Token(TokenType.CUANTIFICADOR, caracter)

        if caracter == '+':
            self.pos += 1
            return Token(TokenType.CUANTIFICADOR, caracter)

        if caracter == '?':
            self.pos += 1
            return Token(TokenType.CUANTIFICADOR, caracter)

        if caracter == '|':
            self.pos += 1
            return Token(TokenType.OR, caracter)

        if caracter == ']':
            self.pos += 1
            return Token(TokenType.CIERRA_CORCHETE, caracter)

        raise Exception(f'Caracter no reconocido: {caracter}')

    def tokenizar(self):
        while True:
            token = self.obtener_siguiente_token()
            if token.tipo == TokenType.EOF:
                break
            self.tokens.append(token)

        return self.tokens

