import threading
import time
import random
import logging
from queue import Queue

logging.basicConfig(level=logging.INFO)

class Conexion:
    def __init__(self, id):
        self.id = id
        self.conectado = False

    def conectar(self):
        # Simulación de conexión
        self.conectado = True
        logging.info(f"Conexión {self.id} establecida")

    def desconectar(self):
        # Simulación de desconexión
        self.conectado = False
        logging.info(f"Conexión {self.id} cerrada")

    def health_check(self):
        # Simulación de health-check
        return random.choice([True, False])

class PoolConexiones:
    def __init__(self, tamano_pool, timeout_conexion=5):
        if tamano_pool <= 0:
            raise ValueError("El tamaño del pool de conexiones debe ser mayor que 0")
        if timeout_conexion < 0:
            raise ValueError("El timeout de conexión no puede ser negativo")

        self.tamano_pool = tamano_pool
        self.timeout_conexion = timeout_conexion
        self.conexiones = [Conexion(i) for i in range(tamano_pool)]
        self.conexiones_disponibles = Queue(tamano_pool)
        self.lock = threading.Lock()

        for conexion in self.conexiones:
            self.conexiones_disponibles.put(conexion)

    def obtener_conexion(self):
        with self.lock:
            try:
                conexion = self.conexiones_disponibles.get(timeout=self.timeout_conexion)
                conexion.conectar()
                return conexion
            except Exception as e:
                logging.warning(f"No hay conexiones disponibles: {e}")
                return None

    def devolver_conexion(self, conexion):
        if conexion:
            with self.lock:
                conexion.desconectar()
                self.conexiones_disponibles.put(conexion)

    def health_check_conexiones(self):
        with self.lock:
            for conexion in list(self.conexiones):
                if not conexion.health_check():
                    logging.warning(f"Conexión {conexion.id} no respondió al health-check")
                    self.conexiones_disponibles.put(conexion)

def worker(pool, id):
    conexion = pool.obtener_conexion()
    if conexion:
        logging.info(f"Trabajador {id} utilizando conexión {conexion.id}")
        time.sleep(2)  # Simulación de trabajo
        pool.devolver_conexion(conexion)
    else:
        logging.warning(f"Trabajador {id} no pudo obtener conexión")

def main():
    pool = PoolConexiones(5)

    # Iniciar health-check en segundo plano
    def health_check_periodico():
        while True:
            pool.health_check_conexiones()
            time.sleep(10)

    threading.Thread(target=health_check_periodico).start()

    # Simulación de trabajadores
    for i in range(10):
        threading.Thread(target=worker, args=(pool, i)).start()

if __name__ == "__main__":
    main()
