        if archivo.nombre in self.archivos:
            raise ValueError("El archivo ya existe en el repositorio")
        self.archivos[archivo.nombre] = archivo

    def commit(self, mensaje):
        if not self.archivos:
            raise ValueError("No hay archivos en el repositorio para commitear")
        archivos_commit = []
        for nombre, archivo in self.archivos.items():
            hash_archivo = hashlib.sha256(archivo.contenido.encode()).hexdigest()
            archivos_commit.append((nombre, hash_archivo))
        commit = Commit(archivos_commit, mensaje)
        self.commits.append(commit)

