import re

class RegexParser:
    def __init__(self, pattern):
        self.pattern = pattern
        self.index = 0

    def parse(self):
        if not self.pattern:
            raise ValueError("Expresión regular vacía")
        result = self.parse_expression()
        if self.index < len(self.pattern):
            raise ValueError("Expresión regular inválida")
        return result

    def parse_expression(self):
        result = self.parse_term()
        while self.index < len(self.pattern) and self.pattern[self.index] in "+|":
            operator = self.pattern[self.index]
            self.index += 1
            term = self.parse_term()
            if operator == "+":
                result += term
            elif operator == "|":
                result = (result, term)
        return result

    def parse_term(self):
        result = self.parse_factor()
        while self.index < len(self.pattern) and self.pattern[self.index] == "*":
            self.index += 1
            result = {"type": "star", "value": result}
        return result

    def parse_factor(self):
        if self.index >= len(self.pattern):
            raise ValueError("Expresión regular inválida")
        char = self.pattern[self.index]
        self.index += 1
        if char == "(":
            result = self.parse_expression()
            if self.index >= len(self.pattern) or self.pattern[self.index]!= ")":
                raise ValueError("Expresión regular inválida")
            self.index += 1
            return result
        elif char == ")":
            raise ValueError("Expresión regular inválida")
        else:
            return char

    def match(self, string):
        def match_expression(expression, string):
            if isinstance(expression, tuple):
                return match_expression(expression[0], string) or match_expression(expression[1], string)
            elif isinstance(expression, dict) and expression["type"] == "star":
                return match_expression_star(expression["value"], string)
            else:
                return string.startswith(expression)

        def match_expression_star(expression, string):
            for i in range(len(string) + 1):
                if match_expression(expression, string[i:]):
                    return True
            return False

        if not string:
            return match_expression(self.parse(), "")
        return match_expression(self.parse(), string)


def regex_match(pattern, string):
    parser = RegexParser(pattern)
    try:
        return parser.match(string)
    except ValueError:
        return False


# Ejemplos de uso
print(regex_match("a*b", "aaab"))  # True
print(regex_match("a*b", "b"))  # True
print(regex_match("a*b", "aaac"))  # False
print(regex_match("(a|b)*", "abab"))  # True
print(regex_match("(a|b)*", "abc"))  # False
