from typing import Callable, Any
from collections import defaultdict

class PubSub:
    def __init__(self):
        self.subscribers = defaultdict(list)

    def subscribe(self, topic: str, predicate: Callable[[Any], bool] = None):
        """
        Suscribir una función a un tema con un predicado opcional.

        Args:
        - topic (str): El tema al que se suscribe.
        - predicate (Callable[[Any], bool], optional): El predicado para filtrar mensajes. Defaults to None.

        Returns:
        - decorator: Un decorador que se aplica a la función a suscribir.
        """
        if not topic:
            raise ValueError("El tema no puede ser vacío o None")

        def decorator(func: Callable[[Any], None]):
            if not callable(func):
                raise ValueError("La función pasada no es callable")

            self.subscribers[topic].append((func, predicate))
            return func
        return decorator

    def publish(self, topic: str, message: Any):
        """
        Publicar un mensaje en un tema.

        Args:
        - topic (str): El tema donde se publica el mensaje.
        - message (Any): El mensaje a publicar.

        Raises:
        - ValueError: Si el tema es vacío o None.
        """
        if not topic:
            raise ValueError("El tema no puede ser vacío o None")
        if message is None:
            print("Warning: Mensaje None publicado en tema", topic)

        if topic not in self.subscribers:
            print(f"Warning: Tema '{topic}' no tiene subscriptores")

        for func, predicate in self.subscribers[topic]:
            if predicate is None or predicate(message):
                func(message)

    def unsubscribe(self, topic: str, func: Callable[[Any], None]):
        """
        Desuscribir una función de un tema.

        Args:
        - topic (str): El tema del que se desuscribe.
        - func (Callable[[Any], None]): La función a desuscribir.

        Raises:
        - ValueError: Si el tema es vacío o None.
        - ValueError: Si la función no está suscrita al tema.
        """
        if not topic:
            raise ValueError("El tema no puede ser vacío o None")

        if topic not in self.subscribers:
            print(f"Warning: Tema '{topic}' no tiene subscriptores")
            return

        original_len = len(self.subscribers[topic])
        self.subscribers[topic] = [(f, p) for f, p in self.subscribers[topic] if f!= func]

        if len(self.subscribers[topic]) == original_len:
            print(f"Warning: Función {func.__name__} no está suscrita al tema '{topic}'")

def main():
    pubsub = PubSub()

    @pubsub.subscribe('topic1')
    def handle_topic1(message):
        print(f"Recibido en topic1: {message}")

    @pubsub.subscribe('topic1', lambda x: x > 5)
    def handle_topic1_filtered(message):
        print(f"Recibido en topic1 (filtrado): {message}")

    @pubsub.subscribe('topic2')
    def handle_topic2(message):
        print(f"Recibido en topic2: {message}")

    pubsub.publish('topic1', 3)
    pubsub.publish('topic1', 7)
    pubsub.publish('topic2', "Hola")

    pubsub.unsubscribe('topic1', handle_topic1)
    pubsub.publish('topic1', 10)

if __name__ == "__main__":
    main()
