import enum

class TokenType(enum.Enum):
    LITERAL = 1
    OR = 2
    CONCAT = 3
    ZERO_OR_MORE = 4
    ONE_OR_MORE = 5
    ZERO_OR_ONE = 6
    GROUP = 7
    START = 8
    END = 9

class Token:
    def __init__(self, type, value):
        self.type = type
        self.value = value

    def __repr__(self):
        return f'Token({self.type}, {self.value})'

class Lexer:
    def __init__(self, pattern):
        self.pattern = pattern
        self.pos = 0

    def get_token(self):
        if self.pos >= len(self.pattern):
            return Token(TokenType.END, None)

        if self.pattern[self.pos] == '|':
            self.pos += 1
            return Token(TokenType.OR, '|')

        if self.pattern[self.pos] == '(':
            self.pos += 1
            return Token(TokenType.GROUP, '(')

        if self.pattern[self.pos] == ')':
            self.pos += 1
            return Token(TokenType.GROUP, ')')

        if self.pattern[self.pos] == '*':
            self.pos += 1
            return Token(TokenType.ZERO_OR_MORE, '*')

        if self.pattern[self.pos] == '+':
            self.pos += 1
            return Token(TokenType.ONE_OR_MORE, '+')

        if self.pattern[self.pos] == '?':
            self.pos += 1
            return Token(TokenType.ZERO_OR_ONE, '?')

        if self.pattern[self.pos] in ['{', '[', ']', '}']:
            raise Exception('Carácter no válido en la expresión regular')

        literal = self.pattern[self.pos]
        self.pos += 1
        return Token(TokenType.LITERAL, literal)

class Parser:
    def __init__(self, lexer):
        self.lexer = lexer
        self.token = self.lexer.get_token()

    def parse(self):
        expr = self.parse_expr()
        if self.token.type != TokenType.END:
            raise Exception('Expected end of input')
        return expr

    def parse_expr(self):
        if self.token.type == TokenType.END:
            return ''
        term = self.parse_term()
