        factor = self.parse_factor()
        while self.token.type == TokenType.CONCAT:
            self.token = self.lexer.get_token()
            factor2 = self.parse_factor()
            factor = ('.', factor, factor2)
        return factor

    def parse_factor(self):
        if self.token.type == TokenType.LITERAL:
            literal = self.token.value
            self.token = self.lexer.get_token()
            return literal
        elif self.token.type == TokenType.GROUP:
            self.token = self.lexer.get_token()
            expr = self.parse_expr()
            if self.token.type != TokenType.GROUP:
