logging.basicConfig(level=logging.INFO)

class CircuitBreaker:
    def __init__(self, threshold, timeout):
        if threshold <= 0 or timeout <= 0:
            raise ValueError("Threshold y timeout deben ser números positivos")
        self.threshold = threshold
        self.timeout = timeout
        self.failures = 0
        self.circuit_open = False
        self.opened_at = None
        self.lock = Lock()

    def is_open(self):
        with self.lock:
            if self.circuit_open:
                if time.time() - self.opened_at > self.timeout:
                    self.circuit_open = False
                    self.failures = 0
            return self.circuit_open

    def try_execute(self, func):
        if self.is_open():
            raise Exception("Circuit is open")
        try:
            return func()
        except Exception as e:
            with self.lock:
                self.failures += 1
                if self.failures >= self.threshold:
                    self.circuit_open = True
                    self.opened_at = time.time()
            raise e


class Backoff:
    def __init__(self, initial_delay, max_delay, multiplier):
        if initial_delay <= 0 or max_delay <= 0 or multiplier <= 0:
            raise ValueError("Retraso inicial, retraso máximo y multiplicador deben ser números positivos")
        self.initial_delay = initial_delay
        self.max_delay = max_delay
        self.multiplier = multiplier
        self.delay = initial_delay

    def backoff(self):
        self.delay = min(self.delay * self.multiplier, self.max_delay)
        time.sleep(self.delay)


class RetryError(Exception):
    pass


