    for attempt in range(max_retries):
        try:
            return circuit_breaker.try_execute(func)
        except Exception as e:
            logging.info(f"Intento {attempt+1} fallido: {str(e)}")
            backoff.backoff()
    raise RetryError("Se han agotado los reintentos")


