            self.grafo.add_edge(tarea2.nombre, tarea1.nombre)
            self.tareas_dependientes[tarea2.nombre].add(tarea1.nombre)

    def ejecutar(self):
        # Verificar si el grafo tiene ciclos
        if not nx.is_directed_acyclic_graph(self.grafo):
            raise ValueError("El grafo tiene ciclos")

        # Crear una cola para almacenar las tareas listas para ejecutar
        cola = Queue()

        # Agregar las tareas sin dependencias a la cola
        for tarea in self.tareas.values():
            if not tarea.dependencias:
                cola.put(tarea)

        # Crear un diccionario para almacenar los hilos de ejecución
        hilos = {}

