                tarea.ejecutada = True
                # Agregar las tareas que dependen de la tarea ejecutada a la cola
                for tarea_dependiente in self.tareas_dependientes[tarea.nombre]:
                    tarea_dependiente_obj = self.tareas[tarea_dependiente]
                    tarea_dependiente_obj.dependencias.discard(tarea)
                    if not tarea_dependiente_obj.dependencias:
                        cola.put(tarea_dependiente_obj)

        # Ejecutar las tareas en paralelo
        while not cola.empty():
            tarea = cola.get()
            hilo = threading.Thread(target=ejecutar_tarea, args=(tarea,))
            hilos[tarea.nombre] = hilo
            hilo.start()

        # Esperar a que todos los hilos terminen
        for hilo in hilos.values():
            hilo.join()

