class PubSubSystem:
    """
    Sistema de publicación y suscripción con filtros por predicado.
    """

    def __init__(self):
        """
        Inicializa el sistema de publicación y suscripción.
        """
        self.subscribers = {}

    def subscribe(self, topic: str, predicate=None):
        """
        Suscribe un predicado a un tema.

        Args:
            topic (str): El tema al que se suscribe.
            predicate (callable, optional): El predicado que se aplica al mensaje. Defaults to None.
        """
        if topic is None:
            raise ValueError("El tema no puede ser None")
        if predicate is not None and not callable(predicate):
            raise ValueError("El predicado debe ser una función")

        if topic not in self.subscribers:
            self.subscribers[topic] = set()
        self.subscribers[topic].add(predicate)

    def unsubscribe(self, topic: str, predicate=None):
        """
        Desuscribe un predicado de un tema.

        Args:
            topic (str): El tema del que se desuscribe.
            predicate (callable, optional): El predicado que se desuscribe. Defaults to None.
        """
        if topic is None:
            raise ValueError("El tema no puede ser None")
        if topic not in self.subscribers:
            raise ValueError("El tema no existe")

        if predicate is None:
            self.subscribers[topic] = {None}
        else:
            self.subscribers[topic].discard(predicate)

    def publish(self, topic: str, message):
        """
        Publica un mensaje en un tema.

        Args:
            topic (str): El tema en el que se publica el mensaje.
            message: El mensaje que se publica.
        """
        if topic is None:
            raise ValueError("El tema no puede ser None")
        if topic not in self.subscribers:
            print(f"Advertencia: No hay suscriptores para el tema {topic}")

        processed = False
        for predicate in self.subscribers[topic]:
            if predicate is None or predicate(message):
                print(f"Publicado en {topic}: {message}")
                processed = True

        if not processed:
            print(f"Advertencia: El mensaje {message} no fue procesado por ningún suscriptor en el tema {topic}")


def main():
    sistema = PubSubSystem()

    def filtro_par(numero):
        return numero % 2 == 0

    def filtro_impar(numero):
        return numero % 2 != 0

    sistema.subscribe("numeros", filtro_par)
    sistema.subscribe("numeros", filtro_impar)

    sistema.publish("numeros", 10)
    sistema.publish("numeros", 11)
    sistema.publish("numeros", 12)

    sistema.unsubscribe("numeros", filtro_par)

    sistema.publish("numeros", 14)
    sistema.publish("numeros", 15)


if __name__ == "__main__":
    main()
