import re

class Token:
    def __init__(self, tipo, valor):
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        return f'Token({self.tipo}, {self.valor})'

class Tokenizador:
    def __init__(self, texto):
        self.texto = texto
        self.posicion = 0
        self.tokens = []

    def obtener_token(self):
        if self.posicion >= len(self.texto):
            return Token('EOF', None)

        if self.texto[self.posicion].isspace():
            self.posicion += 1
            return self.obtener_token()

        if self.texto[self.posicion] == '#':  # Comentario
            while self.posicion < len(self.texto) and self.texto[self.posicion] != '\n':
                self.posicion += 1
            return self.obtener_token()

        if self.texto[self.posicion].isdigit() or self.texto[self.posicion] == '.':  # Número
            return self.obtener_numero()

        if self.texto[self.posicion].isalpha() or self.texto[self.posicion] == '_':  # Identificador
            return self.obtener_identificador()

        operadores = {
            '+': 'SUMA',
            '-': 'RESTA',
            '*': 'MULTIPLICACION',
            '/': 'DIVISION',
            '(': 'PARENTECIS_ABRIR',
            ')': 'PARENTECIS_CERRAR',
        }

        if self.texto[self.posicion] in operadores:
            self.posicion += 1
            return Token(operadores[self.texto[self.posicion - 1]], self.texto[self.posicion - 1])

        raise Exception(f'Caracter no reconocido: {self.texto[self.posicion]}')

    def obtener_numero(self):
        match = re.match(r'\d+(?:\.\d+)?', self.texto[self.posicion:])
        if match:
            try:
                numero = float(match.group())
                self.posicion += match.end()
                return Token('NUMERO', numero)
            except ValueError:
                raise Exception(f'Numero no valido: {self.texto[self.posicion:]}')
        raise Exception(f'Numero no valido: {self.texto[self.posicion:]}')

    def obtener_identificador(self):
        match = re.match(r'[a-zA-Z_][a-zA-Z0-9_]*', self.texto[self.posicion:])
        if match:
            identificador = match.group()
            self.posicion += match.end()
            return Token('IDENTIFICADOR', identificador)
        raise Exception(f'Identificador no valido: {self.texto[self.posicion:]}')

    def tokenizar(self):
        while True:
            token = self.obtener_token()
            if token.tipo == 'EOF':
                break
            self.tokens.append(token)
        return self.tokens

# Ejemplo de uso
