from queue import Queue

logging.basicConfig(level=logging.INFO)

class ConexionNoDisponible(Exception):
    """Excepción personalizada para cuando no hay conexiones disponibles"""
    pass

class Conexion:
    def __init__(self, id):
        self.id = id
        self.conectado = False

    def conectar(self):
        """Simulación de conexión"""
        try:
            self.conectado = True
            logging.info(f"Conexión {self.id} establecida")
        except Exception as e:
            logging.error(f"Error al establecer conexión {self.id}: {str(e)}")

    def desconectar(self):
        """Simulación de desconexión"""
        try:
            self.conectado = False
            logging.info(f"Conexión {self.id} cerrada")
        except Exception as e:
            logging.error(f"Error al cerrar conexión {self.id}: {str(e)}")

    def health_check(self):
        """Simulación de health check"""
        return random.choice([True, False])

class PoolConexiones:
    def __init__(self, tamano_pool, tiempo_chequeo):
        if tamano_pool <= 0:
            raise ValueError("El tamaño del pool de conexiones debe ser mayor que cero")
        if tiempo_chequeo <= 0:
            raise ValueError("El tiempo de chequeo debe ser mayor que cero")

        self.tamano_pool = tamano_pool
        self.tiempo_chequeo = tiempo_chequeo
        self.conexiones = [Conexion(i) for i in range(tamano_pool)]
        self.conexiones_disponibles = Queue(tamano_pool)
        self.lock = threading.Lock()

        # Iniciar conexiones
        for conexion in self.conexiones:
            conexion.conectar()
            self.conexiones_disponibles.put(conexion)

        # Iniciar hilo de health check
        self.hilo_chequeo = threading.Thread(target=self.health_check_periodico)
        self.hilo_chequeo.daemon = True
        self.hilo_chequeo.start()

    def health_check_periodico(self):
        while True:
            with self.lock:
                for conexion in list(self.conexiones):
                    if not conexion.health_check():
                        logging.warning(f"Conexión {conexion.id} no respondió al health check. Reconectando...")
                        try:
                            conexion.desconectar()
                            conexion.conectar()
                            self.conexiones_disponibles.put(conexion)
                        except Exception as e:
                            logging.error(f"Error al reconectar conexión {conexion.id}: {str(e)}")
            time.sleep(self.tiempo_chequeo)

    def obtener_conexion(self):
        try:
            return self.conexiones_disponibles.get(block=False)
        except Exception:
            raise ConexionNoDisponible("No hay conexiones disponibles")

    def devolver_conexion(self, conexion):
        if conexion is None or not isinstance(conexion, Conexion):
            logging.error("Conexión inválida")
            return
        with self.lock:
            self.conexiones_disponibles.put(conexion)

def main():
    pool = PoolConexiones(5, 5)

    while True:
        try:
            conexion = pool.obtener_conexion()
            logging.info(f"Obtuve conexión {conexion.id}")
            # Simulación de uso de la conexión
            time.sleep(2)
            pool.devolver_conexion(conexion)
        except ConexionNoDisponible as e:
            logging.error(str(e))
        except Exception as e:
            logging.error(str(e))

if __name__ == "__main__":
    main()
