class PoolConexiones:
    def __init__(self, host, database, user, password, max_conexiones=10, max_reintentos=3):
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.max_conexiones = max_conexiones
        self.max_reintentos = max_reintentos
        self.conexiones = queue.Queue(max_conexiones)
        self.lock = threading.Lock()
        self.conexiones_activas = 0

        for _ in range(max_conexiones):
            conexion = self.crear_conexion()
            if conexion:
                self.conexiones.put(conexion)
                self.conexiones_activas += 1

    def crear_conexion(self):
        for _ in range(self.max_reintentos):
            conexion = Conexion(self.host, self.database, self.user, self.password)
            if conexion.conectar():
                return conexion
            else:
                logger.error("No se pudo conectar, reintento...")
                time.sleep(1)
        logger.error("No se pudo conectar después de {} reintentos".format(self.max_reintentos))
        return None

    def obtener_conexion(self):
        with self.lock:
            if not self.conexiones.empty():
                conexion = self.conexiones.get()
                if conexion.health_check():
                    return conexion
                else:
                    conexion.desconectar()
                    logger.error("Conexión no saludable, se descarta")
                    self.conexiones_activas -= 1
            else:
                logger.error("No hay conexiones disponibles")

            # Si no hay conexiones disponibles o saludables, creamos una nueva
            if self.conexiones_activas < self.max_conexiones:
                nueva_conexion = self.crear_conexion()
                if nueva_conexion:
                    self.conexiones_activas += 1
                    return nueva_conexion
                else:
