                    return None
            else:
                logger.error("No se puede crear una nueva conexión, pool lleno")
                return None

    def devolver_conexion(self, conexion):
        with self.lock:
            if self.conexiones.full():
                logger.error("No se puede devolver la conexión, pool lleno")
                conexion.desconectar()
                self.conexiones_activas -= 1
            else:
