import threading
import time
import random
import queue
import logging

logging.basicConfig(level=logging.INFO)

class Conexion:
    def __init__(self, id):
        self.id = id
        self.estado = True

    def health_check(self):
        # Simulación de health check
        self.estado = random.choice([True, False])
        return self.estado

    def __str__(self):
        return f"Conexion {self.id} - Estado: {self.estado}"

class PoolConexiones:
    def __init__(self, tamano_pool, tiempo_health_check):
        if tamano_pool <= 0:
            raise ValueError("El tamaño del pool debe ser mayor que 0")
        if tiempo_health_check <= 0:
            raise ValueError("El tiempo de health check debe ser mayor que 0")

        self.tamano_pool = tamano_pool
        self.tiempo_health_check = tiempo_health_check
        self.conexiones = [Conexion(i) for i in range(tamano_pool)]
        self.lock = threading.Lock()
        self.queue_conexiones = queue.Queue()

        # Iniciar health check en segundo plano
        self.hilo_health_check = threading.Thread(target=self.health_check_periodico)
        self.hilo_health_check.daemon = True
        self.hilo_health_check.start()

        # Iniciar llenado de queue con conexiones
        self.llenar_queue_conexiones()

    def health_check_periodico(self):
        while True:
            time.sleep(self.tiempo_health_check)
            self.health_check_conexiones()

    def health_check_conexiones(self):
        with self.lock:
            conexiones_no_respondieron = [conexion for conexion in self.conexiones if not conexion.health_check()]
            for conexion in conexiones_no_respondieron:
                logging.warning(f"Conexion {conexion.id} no respondio al health check. Se elimina del pool.")
                self.conexiones.remove(conexion)
                if len(self.conexiones) < self.tamano_pool:
                    self.conexiones.append(Conexion(len(self.conexiones)))

    def llenar_queue_conexiones(self):
        with self.lock:
            for conexion in self.conexiones:
                self.queue_conexiones.put(conexion)

    def obtener_conexion(self):
        try:
            return self.queue_conexiones.get(block=False)
        except queue.Empty:
            logging.warning("No hay conexiones disponibles en el pool. Se crea una nueva.")
            with self.lock:
                if len(self.conexiones) < self.tamano_pool:
                    nueva_conexion = Conexion(len(self.conexiones))
                    self.conexiones.append(nueva_conexion)
                    return nueva_conexion
                else:
                    raise Exception("No se pueden crear más conexiones. El pool está lleno.")

    def devolver_conexion(self, conexion):
        if conexion in self.conexiones:
            self.queue_conexiones.put(conexion)
        else:
            logging.warning(f"La conexión {conexion.id} no es válida o no existe en el pool.")

def main():
