    def __init__(self, nombre: str, tipo: str):
        self.nombre = nombre
        self.tipo = tipo

class Modelo:
    def __init__(self, nombre: str):
        self.nombre = nombre
        self.campos = {}

    def agregar_campo(self, campo: Campo):
        self.campos[campo.nombre] = campo

class BaseDeDatos:
    def __init__(self, nombre: str):
        self.nombre = nombre
        self.conexion = sqlite3.connect(nombre)
        self.cursor = self.conexion.cursor()

    def crear_tabla(self, modelo: Modelo):
        if not modelo.campos:
            raise ValueError("El modelo no tiene campos")

        campos = ", ".join([f"{campo.nombre} {campo.tipo}" for campo in modelo.campos.values()])
        query = f"CREATE TABLE IF NOT EXISTS {modelo.nombre} (id INTEGER PRIMARY KEY, {campos})"
        try:
            self.cursor.execute(query)
            self.conexion.commit()
        except sqlite3.OperationalError as e:
            print(f"Error al crear la tabla: {e}")

    def insertar(self, modelo: Modelo, datos: Dict[str, str]):
        if not modelo.campos:
            raise ValueError("El modelo no tiene campos")

        campos = ", ".join(datos.keys())
        valores = ", ".join(["?"] * len(datos))
        query = f"INSERT INTO {modelo.nombre} ({campos}) VALUES ({valores})"
        try:
            self.cursor.execute(query, list(datos.values()))
            self.conexion.commit()
        except sqlite3.IntegrityError as e:
            print(f"Error al insertar datos: {e}")

    def seleccionar(self, modelo: Modelo, condiciones: Dict[str, str] = None):
        query = f"SELECT * FROM {modelo.nombre}"
        if condiciones:
            condiciones_str = " AND ".join([f"{campo} = '{valor}'" for campo, valor in condiciones.items()])
            query += f" WHERE {condiciones_str}"
        try:
            self.cursor.execute(query)
            return self.cursor.fetchall()
        except sqlite3.OperationalError as e:
            print(f"Error al seleccionar datos: {e}")
            return []

    def actualizar(self, modelo: Modelo, datos: Dict[str, str], condiciones: Dict[str, str]):
        if not condiciones:
            raise ValueError("No se proporcionaron condiciones")

        campos_str = ", ".join([f"{campo} = '{valor}'" for campo, valor in datos.items()])
        condiciones_str = " AND ".join([f"{campo} = '{valor}'" for campo, valor in condiciones.items()])
        query = f"UPDATE {modelo.nombre} SET {campos_str} WHERE {condiciones_str}"
        try:
            self.cursor.execute(query)
            self.conexion.commit()
        except sqlite3.OperationalError as e:
            print(f"Error al actualizar datos: {e}")

    def eliminar(self, modelo: Modelo, condiciones: Dict[str, str]):
        if not condiciones:
            raise ValueError("No se proporcionaron condiciones")

        condiciones_str = " AND ".join([f"{campo} = '{valor}'" for campo, valor in condiciones.items()])
        query = f"DELETE FROM {modelo.nombre} WHERE {condiciones_str}"
        try:
            self.cursor.execute(query)
            self.conexion.commit()
        except sqlite3.OperationalError as e:
            print(f"Error al eliminar datos: {e}")

class Migracion:
    def __init__(self, base_de_datos: BaseDeDatos):
        self.base_de_datos = base_de_datos

    def crear_tabla(self, modelo: Modelo):
        self.base_de_datos.crear_tabla(modelo)

    def agregar_campo(self, modelo: Modelo, campo: Campo):
        if campo.nombre not in modelo.campos:
            raise ValueError("El campo no existe en el modelo")

        query = f"ALTER TABLE {modelo.nombre} ADD COLUMN {campo.nombre} {campo.tipo}"
        try:
            self.base_de_datos.cursor.execute(query)
            self.base_de_datos.conexion.commit()
        except sqlite3.OperationalError as e:
            print(f"Error al agregar campo: {e}")

    def eliminar_campo(self, modelo: Modelo, campo: Campo):
        if campo.nombre not in modelo.campos:
            raise ValueError("El campo no existe en el modelo")

        query = f"ALTER TABLE {modelo.nombre} DROP COLUMN {campo.nombre}"
        try:
            self.base_de_datos.cursor.execute(query)
            self.base_de_datos.conexion.commit()
        except sqlite3.OperationalError as e:
            print(f"Error al eliminar campo: {e}")

