    id: int
    nombre: str
    precio: float

# Definición de migraciones
def create_table_usuario(conn: sqlite3.Connection) -> None:
    """Crea la tabla de usuarios en la base de datos."""
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS usuarios (
            id INTEGER PRIMARY KEY,
            nombre TEXT NOT NULL,
            email TEXT NOT NULL
        );
    """)
    conn.commit()

def create_table_producto(conn: sqlite3.Connection) -> None:
    """Crea la tabla de productos en la base de datos."""
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS productos (
            id INTEGER PRIMARY KEY,
            nombre TEXT NOT NULL,
            precio REAL NOT NULL
        );
    """)
    conn.commit()

def migrate(conn: sqlite3.Connection) -> None:
    """Realiza las migraciones necesarias en la base de datos."""
    create_table_usuario(conn)
    create_table_producto(conn)

# Definición de la clase Database
class Database:
    def __init__(self, db_name: str) -> None:
        """Inicializa la conexión a la base de datos."""
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()
        self.migrate()

    def migrate(self) -> None:
        """Realiza las migraciones necesarias en la base de datos."""
        migrate(self.conn)

    def insert(self, table: str, data: object) -> None:
        """Inserta un registro en la base de datos."""
        if not isinstance(data, (Usuario, Producto)):
            raise ValueError("El objeto debe ser una instancia de Usuario o Producto")

        if table == "usuarios":
            if not isinstance(data, Usuario):
                raise ValueError("El objeto debe ser una instancia de Usuario")
            self.cursor.execute("SELECT * FROM usuarios WHERE id =?", (data.id,))
            if self.cursor.fetchone():
                raise ValueError("El id ya existe en la base de datos")
            self.cursor.execute("INSERT INTO usuarios (id, nombre, email) VALUES (?,?,?)", (data.id, data.nombre, data.email))
        elif table == "productos":
            if not isinstance(data, Producto):
                raise ValueError("El objeto debe ser una instancia de Producto")
            self.cursor.execute("SELECT * FROM productos WHERE id =?", (data.id,))
            if self.cursor.fetchone():
                raise ValueError("El id ya existe en la base de datos")
            self.cursor.execute("INSERT INTO productos (id, nombre, precio) VALUES (?,?,?)", (data.id, data.nombre, data.precio))
        else:
            raise ValueError("La tabla no existe en la base de datos")
        self.conn.commit()

    def select(self, table: str, id: int) -> Optional[tuple]:
        """Selecciona un registro de la base de datos."""
        if table == "usuarios":
            self.cursor.execute("SELECT * FROM usuarios WHERE id =?", (id,))
            return self.cursor.fetchone()
        elif table == "productos":
            self.cursor.execute("SELECT * FROM productos WHERE id =?", (id,))
            return self.cursor.fetchone()
        else:
            raise ValueError("La tabla no existe en la base de datos")

    def close(self) -> None:
        """Cierra la conexión a la base de datos."""
        self.conn.close()

