import threading
from copy import deepcopy

class CopyOnWriteList:
    def __init__(self, initial_list=None):
        self._data = initial_list if initial_list else []
        self._version = 0
        self._lock = threading.Lock()

    def __getitem__(self, index):
        with self._lock:
            if index < 0 or index >= len(self._data):
                raise IndexError("Índice fuera de rango")
            return self._data[index]

    def __len__(self):
        with self._lock:
            return len(self._data)

    def __setitem__(self, index, value):
        if index is None:
            raise TypeError("Índice no puede ser None")
        with self._lock:
            if self._lock.locked():
                raise RuntimeError("No se puede modificar una lista bloqueada")
            if index < 0 or index >= len(self._data):
                raise IndexError("Índice fuera de rango")
            new_data = deepcopy(self._data)
            new_data[index] = value
            self._data = new_data
            self._version += 1

    def __delitem__(self, index):
        with self._lock:
            if self._lock.locked():
                raise RuntimeError("No se puede modificar una lista bloqueada")
            if index < 0 or index >= len(self._data):
                raise IndexError("Índice fuera de rango")
            new_data = deepcopy(self._data)
            del new_data[index]
            self._data = new_data
            self._version += 1

    def append(self, value):
        with self._lock:
            if self._lock.locked():
                raise RuntimeError("No se puede modificar una lista bloqueada")
            new_data = deepcopy(self._data)
            new_data.append(value)
            self._data = new_data
            self._version += 1

    def lock(self):
        self._lock.acquire()

    def unlock(self):
        self._lock.release()

    def get_version(self):
        with self._lock:
            return self._version


class CopyOnWriteDict:
    def __init__(self, initial_dict=None):
        self._data = initial_dict if initial_dict else {}
        self._version = 0
        self._lock = threading.Lock()

    def __getitem__(self, key):
        with self._lock:
            if key not in self._data:
                raise KeyError("Clave no encontrada")
            return self._data[key]

    def __setitem__(self, key, value):
        if key is None:
            raise TypeError("Clave no puede ser None")
        with self._lock:
            if self._lock.locked():
                raise RuntimeError("No se puede modificar un diccionario bloqueado")
            new_data = deepcopy(self._data)
            new_data[key] = value
            self._data = new_data
            self._version += 1

    def __delitem__(self, key):
        with self._lock:
            if self._lock.locked():
                raise RuntimeError("No se puede modificar un diccionario bloqueado")
            if key not in self._data:
                raise KeyError("Clave no encontrada")
            new_data = deepcopy(self._data)
            del new_data[key]
            self._data = new_data
            self._version += 1

    def lock(self):
        self._lock.acquire()

    def unlock(self):
        self._lock.release()

    def get_version(self):
        with self._lock:
            return self._version


