from collections import defaultdict, deque

class Tarea:
    def __init__(self, nombre):
        if not nombre:
            raise ValueError("Nombre de tarea no puede ser vacío")
        self.nombre = nombre
        self.dependencias = set()
        self.dependidos = set()

class Scheduler:
    def __init__(self):
        self.tareas = {}
        self.grafo = defaultdict(list)

    def agregar_tarea(self, nombre):
        if nombre in self.tareas:
            raise ValueError("Tarea ya existe")
        self.tareas[nombre] = Tarea(nombre)

    def agregar_dependencia(self, tarea, dependencia):
        if tarea not in self.tareas or dependencia not in self.tareas:
            raise ValueError("Tarea o dependencia no existente")
        if dependencia in self.tareas[tarea].dependencias:
            raise ValueError("Dependencia ya existe")
        self.tareas[tarea].dependencias.add(dependencia)
        self.tareas[dependencia].dependidos.add(tarea)
        self.grafo[dependencia].append(tarea)

    def orden_topologico(self):
        if not self.tareas:
            raise ValueError("No hay tareas para ordenar")
        grado_entrada = {tarea: 0 for tarea in self.tareas}
        for tarea in self.tareas:
            for dependencia in self.tareas[tarea].dependencias:
                grado_entrada[tarea] += 1

        cola = deque([tarea for tarea in self.tareas if grado_entrada[tarea] == 0])
        orden = []

        while cola:
            tarea = cola.popleft()
            orden.append(tarea)
            for dependido in self.tareas[tarea].dependidos:
                grado_entrada[dependido] -= 1
                if grado_entrada[dependido] == 0:
                    cola.append(dependido)

        if len(orden) != len(self.tareas):
            raise ValueError("Ciclo detectado en el grafo")

        return orden

    def ejecutar_tareas(self):
        if not self.tareas:
            raise ValueError("No hay tareas para ejecutar")
        orden = self.orden_topologico()
        for tarea in orden:
            try:
                print(f"Ejecutando tarea {tarea}")
            except Exception as e:
                print(f"Error al ejecutar tarea {tarea}: {str(e)}")
                break

# Ejemplo de uso
scheduler = Scheduler()
scheduler.agregar_tarea("A")
scheduler.agregar_tarea("B")
scheduler.agregar_tarea("C")
scheduler.agregar_tarea("D")
scheduler.agregar_dependencia("B", "A")
scheduler.agregar_dependencia("C", "A")
scheduler.agregar_dependencia("D", "B")
scheduler.agregar_dependencia("D", "C")
scheduler.ejecutar_tareas()
